    public String getTaskExecuteStatus(String type) 
    {
    	Date date = new Date();
    	SimpleDateFormat dateFormat= new SimpleDateFormat("HH:mm");
    	return MessageFormat.format("{0}:{1}", type, dateFormat.format(date));       
    }
